1	<!doctype html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>ASML Playbook</title>
7	<style>
8	:root {
9	  --sidebar-w: 260px;
10	  --accent: #0066cc;
11	  --accent-light: #e8f0fc;
12	  --text: #1a1a2e;
13	  --muted: #6b7280;
14	  --border: #e5e7eb;
15	  --surface: #f9fafb;
16	  --bear: #dc2626;
17	  --bull: #16a34a;
18	  --base-blue: #2563eb;
19	  --warning: #d97706;
20	  --font: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
21	  --mono: 'SF Mono', 'Fira Code', 'Cascadia Code', Consolas, monospace;
22	}
23	*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
24	html { scroll-behavior: smooth; font-size: 16px; }
25	body { font-family: var(--font); color: var(--text); background: #fff; display: flex; min-height: 100vh; }
26	
27	#sidebar {
28	  position: fixed; top: 0; left: 0;
29	  width: var(--sidebar-w); height: 100vh;
30	  overflow-y: auto;
31	  background: var(--surface); border-right: 1px solid var(--border);
32	  padding: 1.25rem 0; z-index: 100;
33	}
34	#sidebar .toc-title {
35	  font-size: 0.65rem; font-weight: 700;
36	  text-transform: uppercase; letter-spacing: 0.08em;
37	  color: var(--muted); padding: 0 1rem 0.75rem;
38	}
39	#sidebar ul { list-style: none; }
40	#sidebar li a {
41	  display: block; padding: 0.28rem 1rem;
42	  font-size: 0.82rem; color: var(--muted);
43	  text-decoration: none;
44	  border-left: 2px solid transparent;
45	  transition: color 0.15s, border-color 0.15s, background 0.15s;
46	  line-height: 1.35;
47	}
48	#sidebar li.h2 a { font-weight: 600; color: var(--text); padding: 0.4rem 1rem; }
49	#sidebar li.h3 a { padding-left: 1.75rem; font-size: 0.77rem; }
50	#sidebar li a:hover, #sidebar li a.active {
51	  color: var(--accent); border-left-color: var(--accent); background: var(--accent-light);
52	}
53	
54	#main { margin-left: var(--sidebar-w); flex: 1; padding: 2.5rem 3rem 4rem; max-width: 920px; }
55	
56	#doc-header { margin-bottom: 1.75rem; padding-bottom: 1.5rem; border-bottom: 2px solid var(--border); }
57	#doc-header h1 { font-size: 2rem; font-weight: 700; margin-bottom: 0.6rem; }
58	.doc-meta { display: flex; flex-wrap: wrap; gap: 0.4rem; margin-top: 0.6rem; align-items: center; }
59	.chip { display: inline-flex; align-items: center; font-size: 0.72rem; font-weight: 600; padding: 0.2rem 0.6rem; border-radius: 999px; }
60	.chip-blue { background: var(--accent-light); color: var(--accent); }
61	.chip-green { background: #f0fdf4; color: #15803d; }
62	.chip-muted { background: #f3f4f6; color: var(--muted); font-weight: 400; }
63	.chip-amber { background: #fef3c7; color: var(--warning); }
64	.thesis { margin-top: 1rem; font-size: 0.95rem; font-style: italic; color: var(--muted); border-left: 3px solid var(--accent); padding: 0.4rem 0.75rem; }
65	
